import { cn } from '@/utils/cn';
import Eye from 'lucide-solid/icons/eye';
import EyeOff from 'lucide-solid/icons/eye-off';
import { Component, createSignal, createUniqueId, mergeProps } from 'solid-js';
import type { InputPasswordProps } from '../input.types';
import { DEFAULT_PROPS } from '../input.utils';
import { InputText } from './input-text';

export const InputPassword: Component<InputPasswordProps> = (p => {
  p = mergeProps({ ...DEFAULT_PROPS, id: createUniqueId() }, p);

  const [showPassword, setShowPassword] = createSignal(false);
  let timeoutId: ReturnType<typeof setTimeout> | undefined;

  const togglePasswordVisibility = (e: MouseEvent) => {
    e.stopPropagation();
    if (timeoutId !== undefined) {
      clearTimeout(timeoutId);
      timeoutId = undefined;
    }
    const next = !showPassword();
    setShowPassword(next);
    if (next) {
      timeoutId = setTimeout(() => {
        setShowPassword(false);
        timeoutId = undefined;
      }, 1000);
    }
  };

  return (
    <InputText
      {...p}
      type={(showPassword() ? 'text' : 'password') as 'text'}
      typeOrigin="password"
      maskOptions={void 0}
      suffixIcon={
        <div class="ipa01" onClick={togglePasswordVisibility}>
          <EyeOff class={cn('ipa02', showPassword() ? 'opacity-100' : 'opacity-0')} />
          <Eye class={cn('ipa03', !showPassword() ? 'opacity-100' : 'opacity-0')} />
        </div>
      }
    />
  );
}) as Component<InputPasswordProps>;
